        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();

        uint32_t totalElems = rows * dimSize_;

        AscendC::Cast(tmpLocal, maskLocal, 1.0f, (*AscendC::GetRoundMode()), totalElems);
        AscendC::Mul(yLocal, xLocal, tmpLocal, totalElems);

        AscendC::LocalTensor<float> lastRowLocal = lastRowBuf_.AllocTensor<float>();
        AscendC::CumSumInfo cumSumInfo;
        cumSumInfo.rows = rows;
        cumSumInfo.cols = dimSize_;
        AscendC::CumSum(yLocal, lastRowLocal, yLocal, tmpLocal, cumSumInfo);

